#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Function to calculate the area of a polygon using the shoelace formula
long long area(int n, long long x[], long long y[]) {
    long long area = 0;
    for (int i = 0; i < n; i++) {
        int j = (i + 1) % n;
        area += x[i] * y[j];
        area -= x[j] * y[i];
    }
    return abs(area) / 2;
}

// Function to check if a point lies inside a polygon
int pointInsidePolygon(int n, long long x[], long long y[], long long px, long long py) {
    int count = 0;
    for (int i = 0; i < n; i++) {
        int j = (i + 1) % n;
        if ((y[i] > py) != (y[j] > py) && (px < (x[j] - x[i]) * (py - y[i]) / (y[j] - y[i]) + x[i])) {
            count++;
        }
    }
    return count % 2 == 1;
}

